const DUKAAN_MUNIM_INSTRUCTION = `
[SYSTEM_PROTOCOL: MUNIM_INTELLIGENCE_v1M]
Role: Principal Digital Munim for Indian Kirana Shops.

Logic Requirements: 
1. LOGIC DECOMPOSITION: Explicitly state the reasoning steps taken.
2. INTENT HYPOTHESIS: If message is "Rahul 500", hypothesize if it's a NEW_BILL based on local retail heuristics.
3. STRATEGIC INSIGHT: Identify the financial risk profile of the transaction.

STRICT JSON OUTPUT. 
Required Field: 'logic_trace' (Array of strings representing reasoning steps).
Required Field: 'strategic_intent' (Simple string).
`;

const MARKETING_HUB_INSTRUCTION = `
Role: Bharat Retail Marketing Strategist.
Task: Generate persuasive, Hinglish/English marketing copy for Indian Kirana stores.
Tone: Friendly, community-oriented, and professional. 
Format: Short, punchy WhatsApp-ready messages with emojis.
`;

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const parseMessage = async (text: string, context?: string, retries = 2): Promise<ParsedBill & { logic_trace: string[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [{ parts: [{ text: `[STATE]: ${context || 'Initial'}\n[INGRESS]: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_MUNIM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            action: { type: Type.STRING, enum: ["add_entry", "modify_entry", "get_summary", "marketing_gen", "clarification_required"] },
            customer_name: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            items: { type: Type.STRING },
            confidence: { type: Type.NUMBER },
            user_message: { type: Type.STRING },
            strategic_intent: { type: Type.STRING },
            logic_trace: { type: Type.ARRAY, items: { type: Type.STRING } },
            uncertainty_hypotheses: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["action", "confidence", "user_message", "strategic_intent", "logic_trace"]
        },
        thinkingConfig: { thinkingBudget: 8000 }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (error: any) {
    if (retries > 0) {
      await delay(1000);
      return parseMessage(text, context, retries - 1);
    }
    return { 
      action: 'clarification_required', 
      user_message: "Munim link unstable. System entering defensive recovery mode.", 
      confidence: 0.1,
      strategic_intent: "Auto-recovery failover.",
      logic_trace: ["API_FAILURE", "FALLBACK_TRIGGERED"]
    };
  }
};

