import React, { useState } from 'react';
import { AutomationRule, Bill } from '../types';
import { MOCK_AUTOMATIONS, MOCK_BILLS } from '../constants';
import { GeminiService } from '../services/gemini';

const AutomationsView: React.FC = () => {
  const [rules, setRules] = useState<AutomationRule[]>(MOCK_AUTOMATIONS);
  const [bills] = useState<Bill[]>(MOCK_BILLS);
  const [isOptimizing, setIsOptimizing] = useState(false);
  const [optimizations, setOptimizations] = useState<any[]>([]);
  const gemini = new GeminiService();

  const toggleRule = (id: string) => {
    setRules(rules.map(r => r.id === id ? { ...r, isActive: !r.isActive } : r));
  };

  const handleSmartPilot = async () => {
    setIsOptimizing(true);
    const results = await gemini.optimizeAutomationThresholds(rules, bills);
    setOptimizations(results);
    setIsOptimizing(false);
  };

  const applyOptimization = (ruleId: string, threshold: number) => {
    setRules(rules.map(r => r.id === ruleId ? { ...r, threshold } : r));
    setOptimizations(optimizations.filter(o => o.ruleId !== ruleId));
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Rule Engine</h2>
          <p className="text-slate-500 font-medium">Automate engagement based on behavior pulse.</p>
        </div>
        <button 
          className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-700 transition shadow-lg shadow-indigo-200"
        >
          Add New Trigger
        </button>
